mapper.select:
/* SQL ID : QbnkCtgrDAO.profQbnkCtgrList 설 명 : 교수문제은행분류목록조회 */ WITH SBJCT AS ( SELECT SBJCT.SMSTR_CHRT_ID FROM TB_LMS_SBJCT SBJCT JOIN TB_LMS_SBJCT_ADM SBJCT_ADM ON SBJCT.SBJCT_ID = SBJCT_ADM.SBJCT_ID AND SBJCT_ADM_TYCD = 'PROF' WHERE SBJCT.DELYN = 'N' AND SBJCT.USEYN = 'Y' AND SBJCT_ADM.USER_ID = (SELECT MAX(USER_ID) FROM TB_LMS_SBJCT_ADM WHERE SBJCT_ADM_TYCD = 'PROF' AND SBJCT_ID = #{sbjctId}) ) SELECT QBNK_CTGR_ID , CTGRNM FROM TB_LMS_QBNK_CTGR WHERE DELYN = 'N' AND SMSTR_CHRT_ID IN (SELECT SMSTR_CHRT_ID FROM SBJCT) AND USER_RPRS_ID = #{userRprsId}
AND UP_QBNK_CTGR_ID = #{upQbnkCtgrId}
AND UP_QBNK_CTGR_ID IS NULL
ORDER BY CTGR_SEQNO

/* SQL ID : QbnkCtgrDAO.profQbnkCtgrAllList 설 명 : 교수문제은행분류전체목록조회 */ SELECT * FROM ( SELECT ROW_NUMBER() OVER(ORDER BY CTGR.ORDER_CTGR_ID ASC, CTGR.ORDER_SEQNO ASC) AS LINE_NO , CTGR.* , COUNT(CTGR.QBNK_CTGR_ID) OVER() AS TOTAL_CNT FROM ( SELECT CTGR.QBNK_CTGR_ID , CASE WHEN CTGR.UP_QBNK_CTGR_ID IS NULL THEN CTGR.CTGRNM ELSE (SELECT CTGRNM FROM TB_LMS_QBNK_CTGR WHERE QBNK_CTGR_ID = CTGR.UP_QBNK_CTGR_ID) END UP_QBNK_CTGRNM , CASE WHEN CTGR.UP_QBNK_CTGR_ID IS NULL THEN '-' ELSE CTGR.CTGRNM END AS CTGRNM , SBJCT.SBJCTNM , SBJCT.DVCLAS_NO , USR.USERNM , CTGR.REG_DTTM , NVL(CTGR.UP_QBNK_CTGR_ID, CTGR.QBNK_CTGR_ID) AS ORDER_CTGR_ID , CASE WHEN CTGR.UP_QBNK_CTGR_ID IS NULL THEN 1 ELSE 2 END AS ORDER_SEQNO FROM TB_LMS_QBNK_CTGR CTGR LEFT JOIN TB_LMS_SBJCT SBJCT ON CTGR.SBJCT_ID = SBJCT.SBJCT_ID AND SBJCT.DELYN = 'N' AND SBJCT.USEYN = 'Y' LEFT JOIN TB_LMS_SBJCT_ADM SBJCT_ADM ON SBJCT_ADM.SBJCT_ID = SBJCT.SBJCT_ID AND SBJCT_ADM.USER_ID = CTGR.USER_ID AND SBJCT_ADM.SBJCT_ADM_TYCD = 'PROF' AND SBJCT_ADM.SBJCT_ADM_SEQNO = 1 LEFT JOIN TB_LMS_USER USR ON USR.USER_ID = SBJCT_ADM.USER_ID WHERE CTGR.DELYN = 'N'
AND ( CTGR.UP_QBNK_CTGR_ID = #{upQbnkCtgrId} OR CTGR.QBNK_CTGR_ID = #{upQbnkCtgrId} )
AND CTGR.QBNK_CTGR_ID = #{qbnkCtgrId}
AND CTGR.SBJCT_ID = #{sbjctId}
AND CTGR.USER_RPRS_ID = #{userRprsId}
AND ( LOWER(CTGR.CTGRNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(SBJCT.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(USR.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
) CTGR ) A
WHERE LINE_NO BETWEEN #{firstIndex} +1 AND #{firstIndex} + #{listScale}

/* SQL ID : QbnkCtgrDAO.qbnkNextCtgrSeqnoSelect 설 명 : 문제은행다음분류순번조회 */ SELECT NVL(MAX(CTGR_SEQNO), 0) + 1 FROM TB_LMS_QBNK_CTGR WHERE DELYN = 'N'
AND USER_RPRS_ID = #{userRprsId}
AND UP_QBNK_CTGR_ID = #{upQbnkCtgrId}
AND UP_QBNK_CTGR_ID IS NULL

mapper.delete:
		/*
             SQL ID : QbnkCtgrDAO.qbnkCtgrDelete
             설  명 : 문제은행분류삭제
         */
        UPDATE TB_LMS_QBNK_CTGR SET
        	  DELYN = 'Y'
        	, MDFR_ID = #{mdfrId}
        	, MOD_DTTM = FN_DTTM()
         WHERE QBNK_CTGR_ID = #{qbnkCtgrId}
